const chunks = [];
process.stdin.on('data', d => chunks.push(d));
process.stdin.on('end', () => {
  const input = JSON.parse(Buffer.concat(chunks).toString());
  const transcript = input.transcript || [];
  const lastAssistant = [...transcript].reverse().find(m => m.role === 'assistant');
  const hasResearchContent = lastAssistant && (
    /L[0-6]|layer|value chain|decompos|india proxy|thesis|stress.test|reading list|company|business|market|invest|sector|theme/i.test(lastAssistant.content)
  );
  if (hasResearchContent) {
    const disclaimer = '\n\n---\n> **Research purposes only.** Nothing in this output constitutes investment advice, a recommendation, or a solicitation to buy, sell, or hold any security, fund, or financial instrument. I am not a SEBI registered investment advisor. Ameya Pimpalgaonkar is not a SEBI registered investment advisor. Always conduct your own due diligence and consult a SEBI registered investment advisor before making any financial decision.';
    process.stdout.write(JSON.stringify({ type: 'append', content: disclaimer }));
  } else {
    process.stdout.write(JSON.stringify({ type: 'skip' }));
  }
});
"
